import { Alert } from 'react-native';

const apiBaseUrl = 'https://api.example.com';

const callApi = async (endpoint, method = 'GET', body, token) => {
  try {
    const headers = {
      'Content-Type': 'application/json',
      ...(token && { 'Authorization': `Bearer ${token}` })
    };
    
    const response = await fetch(`${apiBaseUrl}${endpoint}`, {
      method,
      headers,
      body: JSON.stringify(body)
    });

    if (!response.ok) {
      throw new Error(`Error: ${response.status}`);
    }

    return await response.json();
  } catch (error) {
    Alert.alert('Network Error', error.message);
    return null;
  }
};

export const login = async (username, password) => {
  return await callApi('/auth/login', 'POST', { username, password });
};

export const fetchUserProfile = async (token) => {
  return await callApi('/user/profile', 'GET', null, token);
};

export const updateUserData = async (token, data) => {
  return await callApi('/user/update', 'PUT', data, token);
};